1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty set when given empty set", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with two live neighbors (survival)", () => {
15	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
16	    expect(result).toContainEqual([0, 0]);
17	  });
18	  it("should keep alive a live cell with three live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("should kill a live cell with more than three live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring to life a dead cell with exactly three live neighbors (reproduction)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it.todo("should preserve a block still life unchanged");
31	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
32	  it.todo("should support negative coordinates");
33	});
34

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const liveSet = new Set<string>(cells.map(cellKey));
13	
14	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const key = cellKey(neighbor);
19	      const existing = neighborCounts.get(key);
20	      neighborCounts.set(key, {
21	        cell: neighbor,
22	        count: (existing?.count ?? 0) + 1,
23	      });
24	    }
25	  }
26	
27	  const result: Cell[] = [];
28	  for (const [key, { cell, count }] of neighborCounts) {
29	    const isAlive = liveSet.has(key);
30	    const survives = isAlive && count === 2;
31	    const isBorn = count === 3;
32	    if (survives || isBorn) {
33	      result.push(cell);
34	    }
35	  }
36	
37	  return result;
38	}
